args.sparql:
SELECT ?team ?teamLabel (COUNT(?game) AS ?wins) WHERE {
  ?game wdt:P31 wd:Q452670.
  ?game wdt:P115 ?team.
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
} GROUP BY ?team ORDER BY DESC(?wins) LIMIT 1

SELECT ?team ?teamLabel (COUNT(?event) AS ?wins)
WHERE {
  ?event wdt:P31 wd:Q12671887;
         p:P156/ps:P156 ?team.
  ?team rdfs:label ?teamLabel.
  FILTER(LANG(?teamLabel) = "en")
}
GROUP BY ?team ?teamLabel
ORDER BY DESC(?wins)
LIMIT 1

SELECT ?team ?teamLabel (COUNT(?event) AS ?wins)
WHERE {
  ?event wdt:P31 wd:Q452670.
  ?event p:P1345 [
    ps:P1345 ?team;
    pq:P1991 ?winner
  ].
  ?team rdfs:label ?teamLabel.
  FILTER(LANG(?teamLabel) = "en").
}
GROUP BY ?team ?teamLabel
ORDER BY DESC(?wins)
LIMIT 1

SELECT ?team ?teamLabel (COUNT(?event) AS ?wins)
WHERE {
